//vip.opstream16.com/share/440bcbe45a6a4e361b606228f0c86365","link_m3u8":"https://vip.opstream16.com/20221205/26953_825cb448/index.m3u8"}]}],"time":"86 phút","description":"<p>Biến Chất - Corrupt xoay quanh trợ lý D.A. Kate MacIntyre đang thực hiện vụ án về Vargano thì hai người đàn ông chủ chốt của vụ truy tố bị giết bởi một tay súng bắn tỉa ngay trước mặt cô. Cảm thấy kinh hoàng trước những vụ giết người, Kate từ bỏ vị trí của mình để trở thành một giảng viên. Nhưng khi sếp cũ của cô, D.A. Frank Murphy, nhờ cô giúp đỡ, cô đồng ý làm cố vấn cùng với Frank và Greg Nealand, trợ lý mới của D.A. Nhưng sự trở lại của Kate khiến cuộc sống của cô rơi vào nguy hiểm.</p>","tmdb":{"type":"movie","id":"387500","season":null,"vote_average":6.5,"vote_count":2},"modified":"2022-12-06T10:03:07.000Z"},{"id":"638eb10abe31c1c97da0466a","_id":"638eb10abe31c1c97da0466a","title":"Ngày Để Chết","origin_name":"Date To Die For","slug":"ngay-de-chet","year":2015,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Ngày Để Chết","link_embed":"https://vip.opstream16.com/share/4254430a132cbc2cfb235d0fca392279","link_m3u8":"https://vip.opstream16.com/20221205/26960_a0d378aa/index.m3u8"}]}],"time":"88 phút","description":"<p>Ngày Để Chết - Date To Die For kể về câu chuyện Laura Armstrong là một bà mẹ hai con đang chuẩn bị ly dị chồng là Derek, một luật sư. Những người bạn của cô khuyến khích cô bắt đầu lại bằng cách hẹn hò với Michael Hill, một người cha đã ly hôn. Buổi sáng sau buổi hẹn hò với Michael, Laura thức dậy mà không nhớ gì về đêm hôm trước hay cô đã lên giường với anh ta như thế nào và kinh hoàng khi thấy anh ta nằm cạnh cô với một con dao đâm vào ngực. Cô bị buộc tội giết người và bị tống vào tù. Khi được tại ngoại, Laura bắt đầu chứng minh sự vô tội của mình, đồng thời cũng đấu tranh để giành quyền nuôi con gái.</p>","tmdb":{"type":"movie","id":"364055","season":null,"vote_average":5.2,"vote_count":10},"modified":"2022-12-06T10:03:38.000Z"},{"id":"638eb138be31c1c97da048e6","_id":"638eb138be31c1c97da048e6","title":"Thanh Tra Ma Cà Rồng","origin_name":"Nocturna","slug":"thanh-tra-ma-ca-rong","year":2015,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"},{"id":"620a22ace0fc277084dfd531","name":"Kinh Dị","slug":"kinh-di"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Thanh Tra Ma Cà Rồng","link_embed":"https://vip.opstream16.com/share/2aad8aa7c3f8e4064e980e9528e50f53","link_m3u8":"https://vip.opstream16.com/20221205/26963_26c02e46/index.m3u8"}]}],"time":"94 phút","description":"<p>Thanh Tra Ma cà Rồng - Nocturna kể về hai thám tử của New Orleans bị cuốn vào mối thù kéo dài hàng thế kỷ giữa hai phe bí mật của thế giới ma cà rồng trong khi điều tra vụ án một đứa trẻ bỏ trốn. Bị giằng xé giữa cuộc sống bình thường và cuộc chiến của những \\</p>","tmdb":{"type":"movie","id":"360321","season":null,"vote_average":3.6,"vote_count":14},"modified":"2022-12-06T10:04:24.000Z"},{"id":"638eb152be31c1c97da04a5d","_id":"638eb152be31c1c97da04a5d","title":"Thần Đồng Bóng Chày","origin_name":"The Phenom","slug":"than-dong-bong-chay","year":2016,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"620